section.code:
{
  "use_case": "indoor furniture try-on",
  "primary_anchor": "horizontal_plane",
  "fallback_chain": ["vertical_plane", "image_marker", "manual_placement"],
  "scale": {
    "unit": "real_world_meters",
    "user_resize": true,
    "max_scale_factor": 1.0
  },
  "tracking": {
    "min_lux": 200,
    "perf_target_fps": 60,
    "perf_min_fps": 30,
    "scan_timeout_s": 8,
    "fallback_on_timeout": true
  },
  "lifecycle": {
    "scan_phase": {
      "user_hint": "Move device slowly across the floor",
      "timeout_s": 8
    },
    "place_phase": {
      "requires_confirmation": true,
      "preview_translucent": true
    },
    "interact_phase": {
      "gestures": ["tap", "drag", "pinch", "two_finger_rotate"],
      "voice_alts": true,
      "gaze_selection": true,
      "gaze_dwell_ms": 1500
    }
  },
  "exit": {
    "always_visible": true,
    "single_tap": true,
    "voice_command": "Exit AR"
  },
  "ar_free_toggle": true,
  "safety_mode": {
    "dim_on_motion": true,
    "obstacle_audio_warning": false
  },
  "lighting": {
    "estimation_enabled": true,
    "shadow_casting": true,
    "warn_below_lux": 200
  },
  "accessibility": {
    "voice_commands": true,
    "high_contrast_option": true,
    "color_blind_safe": true,
    "min_target_dp": 44,
    "adjustable_text_size": true,
    "non_ar_fallback": true,
    "captions": false
  }
}
